@page "/inventory"
@using InventoryApp.Services
@rendermode InteractiveServer
@inject EquipmentService EquipmentSvc
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _items;
    private PersistingComponentStateSubscription _persistSubscription;

    protected override async Task OnInitializedAsync()
    {
        // Register a callback so prerender can persist the data before the
        // response is sent.  This runs only during the static-SSR pass.
        _persistSubscription = ApplicationState.RegisterOnPersisting(PersistData);

        // If the interactive circuit is starting up and the prerendered data is
        // already available, use it instead of calling the service again.
        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>(nameof(_items), out var restored))
        {
            _items = restored;
        }
        else
        {
            _items = await EquipmentSvc.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson(nameof(_items), _items);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _persistSubscription.Dispose();
    }
}

